const ticket = $('Tickets iterieren').first().json;
const embedding = $('Embedding erstellen').first().json.embedding || [];
const similar = $('Ähnliche Lösungen suchen').first().json.result || [];

let context = '';
if (similar.length > 0) {
  context = '\n\nÄhnliche gelöste Tickets aus der Wissensdatenbank:\n' +
    similar.map((s, i) => {
      const p = s.payload || {};
      return `${i + 1}. Ticket #${p.number || '?'}: ${p.subject || ''}\n   Lösung: ${(p.solution || '').slice(0, 300)}`;
    }).join('\n');
}

return [{
  json: {
    ticketId: ticket.id,
    ticketNumber: ticket.number,
    subject: ticket.subject,
    message: ticket.message,
    embedding: embedding,
    prompt: `Ticket-Betreff: ${ticket.subject}\n\nTicket-Inhalt:\n${ticket.message.slice(0, 2000)}${context}\n\nBitte erstelle einen präzisen Lösungsvorschlag auf Deutsch. Gib konkrete Schritte an, wenn möglich. Halte die Antwort unter 500 Wörtern.`
  }
}];

